create table public.reward_credit_allocations(id uuid primary key default gen_random_uuid(),account_id uuid not null references public.reward_accounts(id),debit_ledger_id uuid not null references public.reward_ledger(id),source_credit_id uuid not null references public.reward_ledger(id),amount numeric(12,2)not null check(amount>0),created_at timestamptz not null default now(),unique(debit_ledger_id,source_credit_id));
create table public.redemption_corrections(id uuid primary key default gen_random_uuid(),request_id uuid not null references public.redemption_requests(id),account_id uuid not null references public.reward_accounts(id),quantity numeric(12,2)not null check(quantity>0),reason text not null check(length(trim(reason))>=3),reward_ledger_id uuid references public.reward_ledger(id),created_by uuid not null references public.profiles(id),created_at timestamptz not null default now());
create table public.benefit_usage_adjustments(id uuid primary key default gen_random_uuid(),account_id uuid not null references public.reward_accounts(id),benefit_id text not null references public.benefit_definitions(id),usage_year int not null,quantity numeric(12,2)not null check(quantity<0),correction_id uuid not null unique references public.redemption_corrections(id),created_at timestamptz not null default now());
create trigger allocations_immutable before update or delete on public.reward_credit_allocations for each row execute function public.prevent_immutable_mutation();create trigger corrections_immutable before update or delete on public.redemption_corrections for each row execute function public.prevent_immutable_mutation();create trigger benefit_adjustments_immutable before update or delete on public.benefit_usage_adjustments for each row execute function public.prevent_immutable_mutation();
alter table public.reward_credit_allocations enable row level security;alter table public.redemption_corrections enable row level security;alter table public.benefit_usage_adjustments enable row level security;create policy allocations_staff_read on public.reward_credit_allocations for select to authenticated using(public.is_staff());create policy corrections_account_read on public.redemption_corrections for select to authenticated using(public.can_access_account(account_id)or public.is_staff());create policy adjustments_account_read on public.benefit_usage_adjustments for select to authenticated using(public.can_access_account(account_id)or public.is_staff());grant select on public.redemption_corrections to authenticated;revoke all on public.reward_credit_allocations,public.redemption_corrections,public.benefit_usage_adjustments from anon;
create or replace function public.available_reward_credit(p_account uuid,p_at timestamptz default now())returns numeric language sql stable security definer set search_path=public as $$select coalesce(sum(case when l.amount>0 and(l.expires_at is null or l.expires_at>p_at)then l.amount-coalesce((select sum(a.amount)from public.reward_credit_allocations a where a.source_credit_id=l.id),0)when l.amount<0 and(l.expires_at is null or l.expires_at>p_at)and not exists(select 1 from public.reward_credit_allocations a where a.debit_ledger_id=l.id)then l.amount else 0 end),0)from public.reward_ledger l where l.account_id=p_account and l.reward_type='reward_credit_usd'$$;revoke execute on function public.available_reward_credit(uuid,timestamptz)from public,anon;grant execute on function public.available_reward_credit(uuid,timestamptz)to authenticated;
create or replace view public.account_benefit_usage with(security_invoker=true)as select account_id,benefit_id,usage_year,sum(quantity)quantity_used from(select account_id,benefit_id,usage_year,quantity from public.benefit_usage union all select account_id,benefit_id,usage_year,quantity from public.benefit_usage_adjustments)x group by account_id,benefit_id,usage_year;
create or replace function public.submit_credit_redemption(p_account_id uuid,p_amount numeric,p_notes text,p_order_reference text,p_idempotency_key uuid)returns uuid language plpgsql security definer set search_path=public as $$declare r uuid;balance numeric;reserved numeric;begin if not public.can_access_account(p_account_id)then raise exception'Account access denied';end if;perform pg_advisory_xact_lock(hashtext(p_account_id::text));balance:=public.available_reward_credit(p_account_id);select coalesce(sum(quantity),0)into reserved from public.redemption_requests where account_id=p_account_id and kind='credit'and status in('submitted','approved');if p_amount<=0 or p_amount>balance-reserved then raise exception'Request exceeds available credit';end if;insert into public.redemption_requests(account_id,submitted_by,kind,reward_type,quantity,customer_notes,order_reference,idempotency_key)values(p_account_id,auth.uid(),'credit','reward_credit_usd',p_amount,coalesce(p_notes,''),p_order_reference,p_idempotency_key)returning id into r;insert into public.audit_events(actor_profile_id,event_type,entity_type,entity_id,details)values(auth.uid(),'redemption_submitted','redemption_request',r::text,jsonb_build_object('kind','credit'));return r;end$$;
create or replace function public.review_redemption_request(p_id uuid,p_status public.redemption_status,p_notes text)returns void language plpgsql security definer set search_path=public as $$begin if not public.is_staff()then raise exception'Staff access required';end if;if p_status not in('approved','rejected')then raise exception'Invalid review status';end if;if p_status='rejected'and length(trim(coalesce(p_notes,'')))<3 then raise exception'Rejection reason is required';end if;update public.redemption_requests set status=p_status,staff_notes=p_notes,reviewed_by=auth.uid(),reviewed_at=now()where id=p_id and(status='submitted'or(status='approved'and p_status='rejected'));if not found then raise exception'Request cannot be reviewed';end if;insert into public.audit_events(actor_profile_id,event_type,entity_type,entity_id,details)values(auth.uid(),'redemption_reviewed','redemption_request',p_id::text,jsonb_build_object('status',p_status,'notes',p_notes));end$$;
create or replace function public.cancel_redemption_request(p_id uuid)returns void language plpgsql security definer set search_path=public as $$begin update public.redemption_requests set status='cancelled'where id=p_id and submitted_by=auth.uid()and status='submitted';if not found then raise exception'Request cannot be cancelled';end if;insert into public.audit_events(actor_profile_id,event_type,entity_type,entity_id)values(auth.uid(),'redemption_cancelled','redemption_request',p_id::text);end$$;
create or replace function public.fulfill_redemption_request(p_id uuid,p_notes text default null)returns void language plpgsql security definer set search_path=public as $$declare r public.redemption_requests%rowtype;entry uuid:=gen_random_uuid();remaining numeric;take numeric;src record;allowance numeric;used numeric;reserved numeric;begin if not public.is_staff()then raise exception'Staff access required';end if;if length(trim(coalesce(p_notes,'')))<3 then raise exception'Fulfillment reference or notes are required';end if;select*into r from public.redemption_requests where id=p_id for update;if r.status<>'approved'then raise exception'Request is not approved';end if;perform pg_advisory_xact_lock(hashtext(r.account_id::text));if r.kind='benefit'then select annual_allowance into allowance from public.benefit_definitions where id=r.benefit_id;if allowance is not null then select coalesce(quantity_used,0)into used from public.account_benefit_usage where account_id=r.account_id and benefit_id=r.benefit_id and usage_year=r.usage_year;select coalesce(sum(quantity),0)into reserved from public.redemption_requests where account_id=r.account_id and benefit_id=r.benefit_id and usage_year=r.usage_year and status in('submitted','approved')and id<>r.id;if r.quantity>allowance-coalesce(used,0)-reserved then raise exception'Benefit allowance is no longer available';end if;end if;insert into public.benefit_usage(id,account_id,benefit_id,quantity,usage_year,description,recorded_by)values(entry,r.account_id,r.benefit_id,r.quantity,r.usage_year,p_notes,auth.uid());update public.redemption_requests set status='fulfilled',fulfilled_at=now(),benefit_usage_id=entry,staff_notes=p_notes where id=p_id;else if r.quantity>public.available_reward_credit(r.account_id)then raise exception'Credit is no longer available';end if;insert into public.reward_ledger(id,account_id,reward_type,amount,description,created_by)values(entry,r.account_id,r.reward_type,-r.quantity,p_notes,auth.uid());remaining:=r.quantity;for src in select l.id,l.amount-coalesce((select sum(a.amount)from public.reward_credit_allocations a where a.source_credit_id=l.id),0)available from public.reward_ledger l where l.account_id=r.account_id and l.reward_type=r.reward_type and l.amount>0 and(l.expires_at is null or l.expires_at>now())order by l.expires_at asc nulls last,l.created_at,l.id for update loop exit when remaining<=0;take:=least(remaining,src.available);if take>0 then insert into public.reward_credit_allocations(account_id,debit_ledger_id,source_credit_id,amount)values(r.account_id,entry,src.id,take);remaining:=remaining-take;end if;end loop;if remaining>0 then raise exception'Credit allocation failed';end if;update public.redemption_requests set status='fulfilled',fulfilled_at=now(),reward_ledger_id=entry,staff_notes=p_notes where id=p_id;end if;insert into public.audit_events(actor_profile_id,event_type,entity_type,entity_id,details)values(auth.uid(),'redemption_fulfilled','redemption_request',p_id::text,jsonb_build_object('kind',r.kind,'quantity',r.quantity,'notes',p_notes));end$$;
create or replace function public.correct_redemption_request(p_id uuid,p_quantity numeric,p_reason text)returns uuid language plpgsql security definer set search_path=public as $$declare r public.redemption_requests%rowtype;c uuid:=gen_random_uuid();entry uuid;already numeric;begin if not public.is_staff()then raise exception'Staff access required';end if;select*into r from public.redemption_requests where id=p_id for update;if r.status<>'fulfilled'then raise exception'Only fulfilled requests can be corrected';end if;select coalesce(sum(quantity),0)into already from public.redemption_corrections where request_id=p_id;if p_quantity<=0 or p_quantity>r.quantity-already then raise exception'Correction exceeds fulfilled quantity';end if;if length(trim(coalesce(p_reason,'')))<3 then raise exception'Correction reason is required';end if;if r.kind='credit'then entry:=gen_random_uuid();insert into public.reward_ledger(id,account_id,reward_type,amount,description,created_by)values(entry,r.account_id,r.reward_type,p_quantity,'Correction: '||p_reason,auth.uid());end if;insert into public.redemption_corrections(id,request_id,account_id,quantity,reason,reward_ledger_id,created_by)values(c,p_id,r.account_id,p_quantity,p_reason,entry,auth.uid());if r.kind='benefit'then insert into public.benefit_usage_adjustments(account_id,benefit_id,usage_year,quantity,correction_id)values(r.account_id,r.benefit_id,r.usage_year,-p_quantity,c);end if;insert into public.audit_events(actor_profile_id,event_type,entity_type,entity_id,details)values(auth.uid(),'redemption_corrected','redemption_request',p_id::text,jsonb_build_object('quantity',p_quantity,'reason',p_reason));return c;end$$;
revoke execute on function public.correct_redemption_request(uuid,numeric,text)from public,anon;grant execute on function public.correct_redemption_request(uuid,numeric,text)to authenticated;

create or replace function public.get_my_dashboard(p_year integer default extract(year from current_date)::integer, p_account_id uuid default null)
returns jsonb language plpgsql stable security definer set search_path=public as $$
declare
 v_account_id uuid;
 v_tier_id text;
 v_tier_name text;
 v_tier_rank integer;
 v_threshold numeric;
 v_spend numeric;
 v_protected date;
 v_profile_name text;
 v_role public.app_role;
 v_result jsonb;
begin
 if auth.uid() is null then raise exception 'Authentication required'; end if;
 select display_name,role into v_profile_name,v_role from public.profiles where id=auth.uid();
 if p_account_id is not null then
   if not public.can_access_account(p_account_id) then raise exception 'Account access denied'; end if;
   v_account_id:=p_account_id;
 else
   select company_id into v_account_id from public.company_memberships where profile_id=auth.uid() order by is_account_manager desc,created_at limit 1;
   if v_account_id is null then select individual_account_id into v_account_id from public.profiles where id=auth.uid(); end if;
 end if;
 if v_account_id is null then raise exception 'No rewards account is linked'; end if;

 select ct.tier_id,ct.display_name,ct.rank,ct.annual_threshold,ct.protected_through
 into v_tier_id,v_tier_name,v_tier_rank,v_threshold,v_protected
 from public.account_current_tiers ct where ct.account_id=v_account_id;
 select coalesce(annual_qualifying_spend,0) into v_spend from public.account_year_spend where account_id=v_account_id and qualifying_year=p_year;
 v_spend:=coalesce(v_spend,0);

 select jsonb_build_object(
  'profile',jsonb_build_object('firstName',split_part(v_profile_name,' ',1),'role',v_role),
  'account',jsonb_build_object('id',a.id,'displayName',a.display_name,'kind',a.kind),
  'tier',jsonb_build_object('id',coalesce(v_tier_id,'beginner'),'displayName',coalesce(v_tier_name,'Onward Beginner'),'rank',coalesce(v_tier_rank,1),'threshold',coalesce(v_threshold,0),'protectedThrough',v_protected,'currentYearSpend',v_spend),
  'summary',jsonb_build_object(
    'qualifyingOrderCount',(select count(*) from public.orders o where o.account_id=v_account_id and extract(year from o.ordered_at)=p_year and o.qualifying_spend>0),
    'savedThisYear',(select coalesce(sum(o.savings_amount),0) from public.orders o where o.account_id=v_account_id and extract(year from o.ordered_at)=p_year),
    'availableCredit',public.available_reward_credit(v_account_id)
  ),
  'benefits',coalesce((select jsonb_agg(jsonb_build_object('id',b.id,'name',b.name,'unit',b.unit,'allowance',b.annual_allowance,'used',coalesce(u.used,0)) order by b.id)
    from public.benefit_definitions b
    left join (select benefit_id,sum(quantity_used) used from public.account_benefit_usage where account_id=v_account_id and usage_year=p_year group by benefit_id) u on u.benefit_id=b.id
    where b.active and b.tier_id=coalesce(v_tier_id,'beginner')),'[]'::jsonb),
  'discounts',coalesce((select jsonb_agg(jsonb_build_object('id',d.id,'name',d.name,'value',d.value,'valueType',d.value_type,'stackable',d.stackable,'description',d.description,'status',ad.status) order by d.stackable,d.id)
    from public.account_discounts ad join public.discount_definitions d on d.id=ad.discount_id where ad.account_id=v_account_id and d.active and (ad.expires_at is null or ad.expires_at>now())),'[]'::jsonb),
  'activity',coalesce((select jsonb_agg(x.obj order by x.ordered_at desc) from (select o.ordered_at,jsonb_build_object('date',to_char(o.ordered_at,'Mon DD, YYYY'),'title',o.order_label,'order',o.external_order_number,'spend',o.qualifying_spend,'savings',o.savings_amount,'status',o.status) obj from public.orders o where o.account_id=v_account_id and extract(year from o.ordered_at)=p_year and o.qualifying_spend>0 order by o.ordered_at desc limit 8) x),'[]'::jsonb),
  'monthlySavings',(select jsonb_agg(jsonb_build_object('month',to_char(make_date(p_year,months.month_num,1),'Mon'),'savings',coalesce(s.amount,0)) order by months.month_num) from generate_series(1,12) as months(month_num) left join (select extract(month from ordered_at)::integer as month_num,sum(savings_amount) amount from public.orders where account_id=v_account_id and extract(year from ordered_at)=p_year group by extract(month from ordered_at)) s on s.month_num=months.month_num)
 ) into v_result from public.reward_accounts a where a.id=v_account_id;
 return v_result;
end; $$;

